import{c as n,Q as a,j as p,m as l}from"./chunks/framework.CBiVa4O3.js";const g=JSON.parse('{"title":"云服务与互联网基础常识总览:为什么应用工程师必须看懂账单和套餐","description":"","frontmatter":{},"headers":[],"relativePath":"../cloudBasicsLearning/01-云服务与互联网基础常识总览.md","filePath":"../cloudBasicsLearning/01-云服务与互联网基础常识总览.md","lastUpdated":1779015580000}'),e={name:"../cloudBasicsLearning/01-云服务与互联网基础常识总览.md"};function t(o,s,i,c,r,u){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="云服务与互联网基础常识总览-为什么应用工程师必须看懂账单和套餐" tabindex="-1">云服务与互联网基础常识总览:为什么应用工程师必须看懂账单和套餐 <a class="header-anchor" href="#云服务与互联网基础常识总览-为什么应用工程师必须看懂账单和套餐" aria-label="Permalink to &quot;云服务与互联网基础常识总览:为什么应用工程师必须看懂账单和套餐&quot;">​</a></h1><p>工程师对「云服务」最大的误解,是把它当成「<strong>运维和 SRE 的事</strong>」——你只管把代码 push 上去,Vercel / Cloudflare / 阿里云会处理剩下的;DNS、HTTPS、CDN、对象存储、Serverless 这些词「<strong>听过就行</strong>」,真正用到的时候再查文档。<strong>这种想法是被 PaaS 一键部署的市场话术长期养出来的幻觉</strong>。真相是:<strong>任何一个独立开发者、SaaS 创始人、做边项目的应用工程师,在 2026 年都要在 30 分钟内做一个有 5-10 个云服务的部署决策</strong>——免费套餐够不够用?Vercel 还是 Cloudflare Pages?对象存储放阿里云 OSS 还是 Cloudflare R2?需不需要 WAF?DNS 该不该托管?证书要不要自己续?<strong>这些决策每一个都直接关系到你能不能上线、上线后会不会被一次流量打爆账单、被一次配置错误导致全站 404</strong>。</p><blockquote><p>一句话先记住:<strong>云服务不是一项技能,是一套常识</strong>。它不要求你能背 AWS 全部产品代号,但要求你<strong>看到一个套餐页、一张架构图、一份账单、一次故障公告时,能立刻知道它在说什么、影响哪一层、风险在哪里、有没有更便宜的替代</strong>。<strong>这个系列教你建立的就是这套常识</strong>——它不深、但它齐;不专、但它能帮你避开 80% 的初学者坑;不绑定任何一个厂商,但让你看任何厂商的产品页都能立即定位它的位置。<strong>做不到这一点,你就只能被云厂商的市场文案牵着走,而账单和故障会教你做人</strong>。</p></blockquote><hr><h2 id="一、为什么应用工程师必须懂云服务常识" tabindex="-1">一、为什么应用工程师必须懂云服务常识 <a class="header-anchor" href="#一、为什么应用工程师必须懂云服务常识" aria-label="Permalink to &quot;一、为什么应用工程师必须懂云服务常识&quot;">​</a></h2><h3 id="_1-1-三个让独立开发者破防的真实场景" tabindex="-1">1.1 三个让独立开发者破防的真实场景 <a class="header-anchor" href="#_1-1-三个让独立开发者破防的真实场景" aria-label="Permalink to &quot;1.1 三个让独立开发者破防的真实场景&quot;">​</a></h3><p><strong>场景 1:Vercel 部署的小项目,月底收到 $80 账单</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你用 Next.js 写了一个边项目,推到 Vercel,绑了自己的域名</span></span>
<span class="line"><span>首页一个看起来人畜无害的「最近文章」组件,用了 SSR</span></span>
<span class="line"><span>没流量的时候它和静态站没区别,你以为「Vercel 免费套餐够了」</span></span>
<span class="line"><span></span></span>
<span class="line"><span>然后某天:</span></span>
<span class="line"><span>  - 一个抖音/小红书博主提到了你的项目</span></span>
<span class="line"><span>  - 12 小时内涌入 2 万 UV</span></span>
<span class="line"><span>  - 你睡着的时候 Vercel 一直在跑 Serverless 函数</span></span>
<span class="line"><span>  - 每个 SSR 请求 = 一次 Function Invocation</span></span>
<span class="line"><span>  - 每次 Function Invocation 还会调 1-2 个 API 路由</span></span>
<span class="line"><span>  - 加上图片优化用了 Image Optimization</span></span>
<span class="line"><span>  - 加上 ISR 重新生成</span></span>
<span class="line"><span></span></span>
<span class="line"><span>月底账单:</span></span>
<span class="line"><span>  - Function Invocations 超额:$30</span></span>
<span class="line"><span>  - Image Optimization 超额:$25</span></span>
<span class="line"><span>  - Bandwidth 超额:$15</span></span>
<span class="line"><span>  - Build Minutes 超额:$10</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>你心想:不是说「免费套餐」吗?</span></span>
<span class="line"><span>打开账单细则:免费套餐只对 Hobby 计划,且超过额度自动切到付费</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>你做错了什么?</span></span>
<span class="line"><span>  - 没把 ISR 改成 SSG</span></span>
<span class="line"><span>  - 没在用户没图片需求的页面禁用 Image Optimization</span></span>
<span class="line"><span>  - 没给账户设预算告警</span></span>
<span class="line"><span>  - 完全不知道 Vercel 的「免费」是按四五个独立维度算的</span></span></code></pre></div><p><strong>这个场景的核心不是「Vercel 黑心」</strong>——而是你<strong>根本不知道一个 Serverless 平台的免费套餐被切成了多少独立维度</strong>:函数调用次数、构建分钟、出站流量、图片优化、ISR 重新生成、KV / Postgres 调用数⋯⋯<strong>它们每一个都有独立额度,任何一个超了都会单独计费</strong>。<strong>所有「我用免费套餐就够」的应用工程师,都在等这一个月</strong>。</p><p><strong>场景 2:域名买了一年,网站访问不了</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你在阿里云买了一个 .com 域名,跟着教程操作</span></span>
<span class="line"><span>  - 注册成功:邮件收到</span></span>
<span class="line"><span>  - 实名认证:通过</span></span>
<span class="line"><span>  - DNS 设置:加了 A 记录指向你 Vultr 上的 VPS</span></span>
<span class="line"><span>  - 浏览器打开:DNS_PROBE_FINISHED_NXDOMAIN</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你 ping 域名:不通</span></span>
<span class="line"><span>你 dig 域名:返回 SERVFAIL</span></span>
<span class="line"><span>你 dig +trace 域名:发现根 DNS 把你指向了阿里云的权威 DNS</span></span>
<span class="line"><span>  阿里云的权威 DNS 返回:NXDOMAIN</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你打电话给阿里云客服:</span></span>
<span class="line"><span>  - 客服 A 说「域名解析需要 24-72 小时生效」(你已等 7 天)</span></span>
<span class="line"><span>  - 客服 B 说「请检查 NS 记录」(你不知道 NS 是什么)</span></span>
<span class="line"><span>  - 客服 C 说「您是不是改了 DNS 服务商但没改注册局的 NS」(没听懂)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最后你才发现:</span></span>
<span class="line"><span>  - 你在「云解析」里加了 A 记录</span></span>
<span class="line"><span>  - 但你在「域名管理」里把 NS 改成了 Cloudflare</span></span>
<span class="line"><span>  - 根 DNS 看到的 NS 是 Cloudflare,所以根本不去查阿里云的 A 记录</span></span>
<span class="line"><span>  - Cloudflare 那边你又没有任何记录,直接返回不存在</span></span></code></pre></div><p><strong>这个场景暴露的是「DNS 不是一个东西」</strong>——它包含<strong>注册局、注册商、注册商的 DNS、第三方权威 DNS、递归 DNS</strong>至少五层,每一层错一个地方都会让网站不通。<strong>而每一层的概念都是云服务的入门常识</strong>——但 99% 的初学者只会跟着「教程」操作,根本不知道自己在哪一层踩到了坑。<strong>这种坑不需要你成为网络专家,只需要你知道「DNS 解析是分层的、域名注册和 DNS 托管是两件事」</strong>——一句话的常识,能省你三天客服扯皮。</p><p><strong>场景 3:数据库连接池打满,Serverless 函数全部 timeout</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的 SaaS 用了:</span></span>
<span class="line"><span>  - Vercel(前端 + API Routes)</span></span>
<span class="line"><span>  - Supabase(Postgres 数据库 + Auth)</span></span>
<span class="line"><span>  - 全免费套餐</span></span>
<span class="line"><span></span></span>
<span class="line"><span>平时 100 DAU,一切正常</span></span>
<span class="line"><span>某天有人在 Twitter / 推特上发了你的产品截图</span></span>
<span class="line"><span>半天涌入 5000 用户,每人打开就触发 10 次 API 请求</span></span>
<span class="line"><span></span></span>
<span class="line"><span>突然所有请求开始 timeout</span></span>
<span class="line"><span>你打开 Vercel 日志:</span></span>
<span class="line"><span>  - &quot;Connection terminated due to connection timeout&quot;</span></span>
<span class="line"><span>  - &quot;Too many connections&quot;</span></span>
<span class="line"><span>  - &quot;FATAL: remaining connection slots are reserved for non-replication superuser connections&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Supabase 免费套餐:max_connections = 60</span></span>
<span class="line"><span>你的 API:每次请求新建一个 Postgres 连接</span></span>
<span class="line"><span>高峰时:5000 用户 × 平均 2 并发 = 10000 个连接尝试</span></span>
<span class="line"><span>60 个槽位瞬间用光,后面全部排队 / 失败</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你的应用对外表现:全站 502 / timeout</span></span>
<span class="line"><span>你的用户体验:点了登录,白屏 30 秒</span></span>
<span class="line"><span>你的获客成本:一次免费 Twitter 流量,全部浪费</span></span>
<span class="line"><span>你的解决方案:升级 Supabase 到 Pro($25/月),max_connections = 200</span></span>
<span class="line"><span>  以及加上 PgBouncer connection pooler</span></span>
<span class="line"><span>  以及把 API 改成连接池复用模式</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>但这一切发生在你已经丢了 5000 个潜在用户之后</span></span></code></pre></div><p><strong>这个场景的核心不是「Supabase 卡」</strong>——而是<strong>你完全不知道「免费套餐」三个字背后藏着多少硬性边界</strong>:数据库最大连接数、对象存储 PUT/GET 次数、Serverless 函数最大执行时间、CDN 缓存命中率、CI 构建分钟⋯⋯<strong>每一个都是一道「玻璃天花板」</strong>,平时撞不到、用户多了一倒头就出事。<strong>所有「我先免费用,等流量来了再升级」的人,都在赌不会被流量打爆</strong>——而**「被流量打爆」恰恰是创业最想要的事**,你不能为它准备好,就等于在最关键的时刻把自己 KO。</p><h3 id="_1-2-这三个场景的共同点" tabindex="-1">1.2 这三个场景的共同点 <a class="header-anchor" href="#_1-2-这三个场景的共同点" aria-label="Permalink to &quot;1.2 这三个场景的共同点&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不是&quot;产品不够好&quot;               —— Vercel / Cloudflare / Supabase 都很好</span></span>
<span class="line"><span>不是&quot;工程师不够强&quot;             —— 都是写代码很熟练的人</span></span>
<span class="line"><span>不是&quot;运气不好&quot;                 —— 一年总会遇到一次</span></span>
<span class="line"><span></span></span>
<span class="line"><span>是&quot;对云服务这一层完全没有心智模型&quot;:</span></span>
<span class="line"><span>   —— 不知道&quot;免费套餐&quot;被切成哪几个独立维度</span></span>
<span class="line"><span>   —— 不知道一次 HTTP 请求穿过几个云组件</span></span>
<span class="line"><span>   —— 不知道哪些限制是&quot;软限制&quot;(超了多收钱),哪些是&quot;硬限制&quot;(超了直接报错)</span></span>
<span class="line"><span>   —— 不知道一份架构图里哪一层是自己负责、哪一层是云厂商负责</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   你不是不会写代码,你只是把&quot;上线&quot;当成了一次性事件</span></span>
<span class="line"><span>   而上线之后,云这一层会一直在那儿,日夜不停地用账单、告警、超额提醒你</span></span></code></pre></div><p><strong>这就是云服务常识要解决的问题</strong>:<strong>让你看任何一个云产品页、任何一份架构图、任何一份账单时,都能立刻定位它在哪一层、限制在哪里、风险点是什么、超额怎么计</strong>。<strong>这不是 SRE 知识,这是应用工程师的基础常识</strong>——就像写代码必须懂 git、懂 SQL 一样,2026 年的工程师必须懂「云这一层是怎么收费、怎么限流、怎么挂掉」的。</p><h3 id="_1-3-不是-云服务-vs-自建-是-看懂你正在用的云服务" tabindex="-1">1.3 不是&quot;云服务 vs 自建&quot;,是&quot;看懂你正在用的云服务&quot; <a class="header-anchor" href="#_1-3-不是-云服务-vs-自建-是-看懂你正在用的云服务" aria-label="Permalink to &quot;1.3 不是&quot;云服务 vs 自建&quot;,是&quot;看懂你正在用的云服务&quot;&quot;">​</a></h3><p>最常见的反驳是「我用 Cloudflare 全免费,根本不用懂这些」——<strong>这个想法本身就反过来证明你必须懂</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你&quot;什么都不懂&quot;的成本,99% 由云厂商替你掩盖了</span></span>
<span class="line"><span>但当那 1% 的事件发生时(账单暴涨 / 流量被切 / 数据库挂掉),</span></span>
<span class="line"><span>你完全没有应对能力,只能去 Twitter / 客服 / GitHub Issue 上求救</span></span>
<span class="line"><span></span></span>
<span class="line"><span>懂常识 vs 不懂常识的真实差异:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不懂的人遇到流量暴涨:</span></span>
<span class="line"><span>   - 收到账单震惊</span></span>
<span class="line"><span>   - 上 Twitter 抱怨&quot;被 Vercel 收割了&quot;</span></span>
<span class="line"><span>   - 临时切到其它平台,损失用户体验</span></span>
<span class="line"><span>   - 半年后再遇一次,重复以上</span></span>
<span class="line"><span></span></span>
<span class="line"><span>懂常识的人遇到流量暴涨:</span></span>
<span class="line"><span>   - 在部署前就给账户加了预算告警</span></span>
<span class="line"><span>   - 在选套餐时就算了 worst-case 月成本</span></span>
<span class="line"><span>   - 看到流量暴涨先看 CDN 缓存命中率(可能 90% 流量根本不该回源)</span></span>
<span class="line"><span>   - 知道把图片优化关掉、ISR 关掉、用静态化能省 80% 的钱</span></span>
<span class="line"><span>   - 提前在 DNS 这一层加了缓存,知道源站故障时切到静态页</span></span></code></pre></div><p><strong>云服务常识是「保险」</strong>:<strong>你不出事它没用,出事的时候它救你的命</strong>。<strong>比起学会写更精巧的代码、用更新的框架,补齐云这一层的常识是 ROI 最高的事</strong>——因为代码错了你可以回滚,云配置错了可能让你一晚上烧掉一个月工资。</p><p>而且,<strong>云服务这一层在 2026 年还在快速分化和兼并</strong>——CDN、对象存储、Serverless、边缘计算这些产品的边界越来越模糊,Cloudflare R2 是对象存储但走 CDN 出口,Vercel Edge Functions 是 Serverless 但跑在 CDN 节点上,Supabase 是数据库但提供 RESTful API⋯⋯<strong>你越懂底层概念,这些&quot;组合产品&quot;在你眼里就越透明;你越不懂,就越被它们的市场命名迷惑</strong>。<strong>这是云服务常识在 2026 年比 2018 年更重要的原因——产品越融合,底层常识越保值</strong>。</p><hr><h2 id="二、云服务常识-vs-「我会用-aws」-的真实分工" tabindex="-1">二、云服务常识 vs 「我会用 AWS」 的真实分工 <a class="header-anchor" href="#二、云服务常识-vs-「我会用-aws」-的真实分工" aria-label="Permalink to &quot;二、云服务常识 vs 「我会用 AWS」 的真实分工&quot;">​</a></h2><p>把这套讲完整,得到一张「常识 vs 操作」的对照表——<strong>这张表你要在白板上能默写</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  &quot;我会用 AWS / 阿里云&quot;擅长                         │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  ✓ 知道在控制台哪里点哪个按钮                                       │</span></span>
<span class="line"><span>│  ✓ 知道 EC2、S3、RDS、CloudFront 的具体名称                       │</span></span>
<span class="line"><span>│  ✓ 会用某个厂商的 CLI / SDK                                       │</span></span>
<span class="line"><span>│  ✓ 能跟着官方教程一步步部署                                         │</span></span>
<span class="line"><span>│  ✓ 在这一家厂商内能闭环工作                                         │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  &quot;云服务常识&quot;擅长                                   │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  ✓ 看到任何厂商的产品页,能映射到通用概念                            │</span></span>
<span class="line"><span>│  ✓ 能算出一个架构在不同厂商的预期成本                                │</span></span>
<span class="line"><span>│  ✓ 能在 5 分钟内判断&quot;这个免费套餐我能用多久&quot;                         │</span></span>
<span class="line"><span>│  ✓ 能从一份账单中找出最大开销并优化                                   │</span></span>
<span class="line"><span>│  ✓ 能从一次故障公告中判断&quot;我会不会被波及&quot;                            │</span></span>
<span class="line"><span>│  ✓ 能在 Cloudflare → Vercel → AWS 三家之间切换并理解差异            │</span></span>
<span class="line"><span>│  ✓ 能跟同事 / 客户讨论架构时使用准确术语                              │</span></span>
<span class="line"><span>│  ✓ 能在不写代码的情况下,光看架构图找出性能瓶颈                         │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>结论</strong>:<strong>「我会用 AWS」是技能,云服务常识是认知</strong>。技能贬值快(三年后你今天会的 AWS 控制台可能 80% 已经改版),认知保值长(DNS / CDN / SLA / IAM 这些概念已经稳定 15-20 年)。<strong>应用工程师应该先有认知,再按需补技能</strong>——而不是反过来,被某一家厂商的具体操作绑住认知。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;我会用 AWS&quot;                  → 一项技能,可以临时学,3-7 天上手</span></span>
<span class="line"><span>&quot;我有云服务常识&quot;               → 一套认知,需要建立框架,3-6 个月内化</span></span>
<span class="line"><span>&quot;我有云服务常识 + 用过 1-2 家&quot; → 应用工程师的合格基线</span></span>
<span class="line"><span>&quot;我有云服务常识 + 跨 3 家做选型&quot; → 创业 / 独立开发的真正护城河</span></span></code></pre></div><p><strong>注意一个反直觉点</strong>:很多人以为「云服务常识」需要先学完「具体某个厂商」才能建立——<strong>实际上是反过来</strong>。如果你先学 AWS 全套(这至少需要半年到一年),你会被它的具体术语绑死,看 Cloudflare / GCP 时就需要从头开始。<strong>先建立通用概念,再把任何一家厂商当成&quot;具体实现&quot;去对照,你的迁移成本就降到接近零</strong>——这就是这个系列要给你的能力。</p><h3 id="_2-1-这个系列不是什么" tabindex="-1">2.1 这个系列不是什么 <a class="header-anchor" href="#_2-1-这个系列不是什么" aria-label="Permalink to &quot;2.1 这个系列不是什么&quot;">​</a></h3><p>为了不让你期望落空,先把这个系列<strong>不是什么</strong>讲清楚:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✗ 不是 AWS Certified Solutions Architect 备考材料</span></span>
<span class="line"><span>   不教考试,不背产品代号,不练实验</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不是 SRE 入门</span></span>
<span class="line"><span>   不教告警系统怎么设计、SLO 怎么定 budget、事故复盘怎么做</span></span>
<span class="line"><span>   只讲应用工程师&quot;看懂&quot;这些概念时需要的常识</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不是某家厂商的操作手册翻译</span></span>
<span class="line"><span>   不教&quot;如何在 AWS 控制台创建 EC2&quot;、&quot;如何在阿里云购买 OSS&quot;</span></span>
<span class="line"><span>   只讲&quot;EC2 / OSS 是什么、什么时候用、有什么限制&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不是网络协议教程</span></span>
<span class="line"><span>   TCP / HTTP / TLS 的细节去 networkLearning 系列</span></span>
<span class="line"><span>   本系列只在涉及 DNS / HTTPS / CDN 时点一下应用工程师必须知道的部分</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不是 Kubernetes / Docker 教程</span></span>
<span class="line"><span>   容器和编排去 backendLearning / devopsLearning</span></span>
<span class="line"><span>   本系列 11-12 只讲&quot;容器 / K8s 作为云产品&quot;的概念位置和成本边界</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不是面试题宝典</span></span>
<span class="line"><span>   不会写&quot;99% 大厂面试题汇总&quot;这种东西</span></span>
<span class="line"><span>   面试用得上的细节会出现,但不是主线</span></span></code></pre></div><p><strong>那这个系列是什么?</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ 一个应用工程师面对&quot;上线一个网站 / SaaS&quot;时,需要的通用常识地图</span></span>
<span class="line"><span>✓ 一份能让你 5 分钟看懂任何云产品页的&quot;翻译手册&quot;</span></span>
<span class="line"><span>✓ 一组能让你避开 80% 初学者坑的&quot;红线提示&quot;</span></span>
<span class="line"><span>✓ 一套&quot;通用概念 + 真实场景&quot;的对照表,看完后任何厂商的产品都不再陌生</span></span></code></pre></div><hr><h2 id="三、42-篇地图-五层结构" tabindex="-1">三、42 篇地图:五层结构 <a class="header-anchor" href="#三、42-篇地图-五层结构" aria-label="Permalink to &quot;三、42 篇地图:五层结构&quot;">​</a></h2><p>把整个系列的 42 篇按层组织,<strong>也可以按你目前的痛点跳读</strong>。先看一张全景图:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 第五层:计费、免费套餐与选型(34-42)                              │</span></span>
<span class="line"><span>│   计费模型 / 免费额度拆解 / 账单与预算 / 主流套餐对比             │</span></span>
<span class="line"><span>│   &quot;为什么我月底账单是 $80&quot;的根因和护栏,9 篇                       │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 第四层:安全、身份与权限(26-33)                                  │</span></span>
<span class="line"><span>│   账号 / IAM / API Key / OAuth / CORS / 防刷 / 合规 / 责任共担   │</span></span>
<span class="line"><span>│   &quot;云厂商负责什么、你负责什么&quot;的边界,8 篇                          │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 第三层:稳定性、可观测性与恢复(18-25)                            │</span></span>
<span class="line"><span>│   SLA / 性能指标 / 监控 / 告警 / 日志 / 备份 / 容灾                │</span></span>
<span class="line"><span>│   &quot;网站会挂、数据会丢&quot;的工程心态,8 篇                              │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 第二层:云资源与部署模型(09-17)                                  │</span></span>
<span class="line"><span>│   服务器 / VPS / 容器 / K8s / Serverless / 静态托管 / 对象存储 / DB │</span></span>
<span class="line"><span>│   &quot;代码怎么变成在线服务&quot;的资源抽象,9 篇                            │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ 第一层:互联网入口与访问链路(01-08)                              │</span></span>
<span class="line"><span>│   总览(本篇) / 域名 / DNS / IP+HTTP / HTTPS / CDN / 反代 / WAF │</span></span>
<span class="line"><span>│   &quot;用户输入 URL 到看见页面&quot;中间的所有云组件,8 篇                    │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_3-1-每层学完能解决什么" tabindex="-1">3.1 每层学完能解决什么 <a class="header-anchor" href="#_3-1-每层学完能解决什么" aria-label="Permalink to &quot;3.1 每层学完能解决什么&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一层(01-08):</span></span>
<span class="line"><span>   学完能在白板上回答:</span></span>
<span class="line"><span>   - &quot;用户输入 URL 到看见页面,中间穿过哪些云组件&quot;</span></span>
<span class="line"><span>   - &quot;DNS 解析为什么有时候要等一天,有时候 30 秒就生效&quot;</span></span>
<span class="line"><span>   - &quot;Cloudflare 的 SSL/TLS 模式 Flexible / Full / Strict 到底有什么区别&quot;</span></span>
<span class="line"><span>   - &quot;CDN 命中率从 60% 提到 95% 能省多少回源带宽费&quot;</span></span>
<span class="line"><span>   - &quot;WAF 拦得住 SQL 注入,拦得住业务逻辑漏洞吗&quot;</span></span>
<span class="line"><span>   解决:对&quot;互联网入口&quot;这一层有完整心智,不会在 DNS / HTTPS / CDN 配置上花一周</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二层(09-17):</span></span>
<span class="line"><span>   学完能回答:</span></span>
<span class="line"><span>   - &quot;我这个项目应该用 VPS、Serverless、还是静态托管&quot;</span></span>
<span class="line"><span>   - &quot;对象存储为什么便宜,放视频流和放数据库备份分别贵在哪&quot;</span></span>
<span class="line"><span>   - &quot;K8s 适不适合我们这种 3 人小团队&quot;(99% 的答案是不适合)</span></span>
<span class="line"><span>   - &quot;Supabase 的免费套餐够撑多少并发&quot;</span></span>
<span class="line"><span>   解决:在&quot;怎么部署&quot;这一层不再二选一焦虑,知道每个产品的位置和边界</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三层(18-25):</span></span>
<span class="line"><span>   学完能回答:</span></span>
<span class="line"><span>   - &quot;Cloudflare 承诺的 100% Uptime SLA 是真的吗&quot;(剧透:是法律意义上的)</span></span>
<span class="line"><span>   - &quot;我的网站 P95 延迟 800ms 是不是不行&quot;(看业务,不看绝对值)</span></span>
<span class="line"><span>   - &quot;免费套餐为什么日志只能保留 3 天,这够不够用&quot;</span></span>
<span class="line"><span>   - &quot;对象存储有 11 个 9 持久性,为什么我还要备份&quot;</span></span>
<span class="line"><span>   解决:不被 SLA 数字迷惑,理解&quot;稳定&quot;和&quot;可观测&quot;是两件事</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四层(26-33):</span></span>
<span class="line"><span>   学完能回答:</span></span>
<span class="line"><span>   - &quot;Root 账号能不能直接拿来 deploy&quot;(不能)</span></span>
<span class="line"><span>   - &quot;API Key 该放环境变量还是 Secrets Manager&quot;</span></span>
<span class="line"><span>   - &quot;前端为什么会有 CORS 错误,后端怎么改才对&quot;</span></span>
<span class="line"><span>   - &quot;为什么 OAuth 比自己写登录系统更安全也更便宜&quot;</span></span>
<span class="line"><span>   - &quot;我们存欧盟用户数据有没有 GDPR 问题&quot;</span></span>
<span class="line"><span>   解决:在&quot;安全&quot;这一层不写出灾难性配置,理解&quot;责任共担&quot;在哪里画线</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第五层(34-42):</span></span>
<span class="line"><span>   学完能回答:</span></span>
<span class="line"><span>   - &quot;我这个架构 worst case 一个月烧多少钱&quot;</span></span>
<span class="line"><span>   - &quot;Vercel / Netlify / Cloudflare Pages / Firebase 我该选哪个&quot;</span></span>
<span class="line"><span>   - &quot;出站流量为什么这么贵,有什么便宜的替代&quot;</span></span>
<span class="line"><span>   - &quot;我的副业项目要不要预先设预算告警&quot;(必须)</span></span>
<span class="line"><span>   解决:对成本和选型有&quot;工程师的直觉&quot;,不再被市场文案带节奏</span></span></code></pre></div><h3 id="_3-2-一个硬指标" tabindex="-1">3.2 一个硬指标 <a class="header-anchor" href="#_3-2-一个硬指标" aria-label="Permalink to &quot;3.2 一个硬指标&quot;">​</a></h3><p>看完 01-08 + 14-15 + 34-42 这 19 篇(也就是「<strong>最小阅读路径</strong>」),你应该能<strong>30 分钟内</strong>对一个新项目做出以下判断:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>□ 域名注册商选哪家、DNS 托管放哪、TTL 设多少</span></span>
<span class="line"><span>□ HTTPS 证书走 Let&#39;s Encrypt 自动续期 还是 Cloudflare 边缘 SSL</span></span>
<span class="line"><span>□ CDN 用 Cloudflare 免费套餐够不够,什么时候要升级</span></span>
<span class="line"><span>□ 静态前端放 Vercel / Netlify / Cloudflare Pages / GitHub Pages 哪个</span></span>
<span class="line"><span>□ 用户上传的文件放哪个对象存储(S3 / R2 / OSS),为什么</span></span>
<span class="line"><span>□ 算出 worst-case 月成本,设一个 5 倍预算告警</span></span>
<span class="line"><span>□ 知道每一个免费套餐的&quot;硬天花板&quot;在哪,什么时候必须升级</span></span></code></pre></div><p><strong>能做到这个,这个系列就值了</strong>。</p><hr><h2 id="四、不同角色的最小阅读路径" tabindex="-1">四、不同角色的最小阅读路径 <a class="header-anchor" href="#四、不同角色的最小阅读路径" aria-label="Permalink to &quot;四、不同角色的最小阅读路径&quot;">​</a></h2><p>不是所有人都要读完 42 篇。按角色给你最小路径——读完这些篇,你对这个角色面对的「云服务问题」就有了基本判断力:</p><table tabindex="0"><thead><tr><th>角色</th><th>必读</th><th>选读</th></tr></thead><tbody><tr><td><strong>独立开发者 / 副业项目</strong></td><td>01-06(入口), 13-15(Serverless / 静态 / 对象存储), 34-35, 39-42(套餐与选型)</td><td>16-17(数据库 / 缓存), 26-28(账号安全)</td></tr><tr><td><strong>SaaS 创始人 / 早期团队</strong></td><td>01-08(全部入口), 13-17(资源全套), 18-19(SLA), 26-28(账号 / IAM / Key), 34-42(选型 + 成本)</td><td>22-25(监控 / 备份), 29-32(合规)</td></tr><tr><td><strong>前端 / 全栈工程师</strong></td><td>01-07(入口), 14(静态托管), 30(CORS), 34-35, 38(构建分钟), 40-41(主流套餐)</td><td>13(Serverless), 15(对象存储)</td></tr><tr><td><strong>后端工程师</strong></td><td>01-04, 09-12(资源 / 容器 / K8s), 15-17(存储 / DB / 缓存), 26-28(IAM / Key), 36-37(流量与请求计费)</td><td>08(DDoS), 18-22(可观测性)</td></tr><tr><td><strong>AI 工程师 / RAG 应用</strong></td><td>01-06, 13(Serverless), 15(对象存储放模型 / 文档), 16(向量库这类托管 DB), 28(API Key), 36(出站流量)</td><td>35-37(各类计费)</td></tr><tr><td><strong>想从&quot;代码党&quot;转型懂部署</strong></td><td>全部第一层 + 14-15 + 34-35 + 40-42</td><td>其它按需</td></tr><tr><td><strong>架构师 / 技术 Lead</strong></td><td>01, 06, 09-10, 13, 15, 18-19, 27, 33, 42</td><td>其它按需</td></tr></tbody></table><p><strong>几个判断点</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- 你打算独立做个 SaaS / 边项目                  → 必须读 01-06, 13-15, 34-42</span></span>
<span class="line"><span>- 你的项目有用户上传(头像 / 文档 / 视频)       → 必须读 15, 36, 37</span></span>
<span class="line"><span>- 你的项目要做支付 / 存欧盟用户                 → 必须读 26-29, 32-33</span></span>
<span class="line"><span>- 你的项目可能突然有流量(被 KOL 提了一下)     → 必须读 06, 08, 18-19, 34, 39</span></span>
<span class="line"><span>- 你之前在大厂,准备出来做小项目                → 必须读 10, 18-19, 34, 39-42(大厂思维下不下来)</span></span>
<span class="line"><span>- 你买过域名但搞不清解析为什么不通              → 必须读 02-04</span></span>
<span class="line"><span>- 你的月度账单已经超出预期                      → 必须读 34-39</span></span></code></pre></div><p><strong>独立开发者的最小路径 = 01-06 + 14-15 + 34-35 + 39-42 = 13 篇</strong>——大约一个月,每周读 2-3 篇,看完你就完成了从「上线靠玄学」到「上线靠工程判断」的转型。</p><hr><h2 id="五、与其他系列的边界" tabindex="-1">五、与其他系列的边界 <a class="header-anchor" href="#五、与其他系列的边界" aria-label="Permalink to &quot;五、与其他系列的边界&quot;">​</a></h2><p>云服务这一层和很多其它技术栈交叉。讲清楚边界,你才知道<strong>遇到一个问题该去哪本系列查</strong>:</p><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列怎么处理</th></tr></thead><tbody><tr><td>TCP / HTTP / TLS / DNS 协议细节</td><td>networkLearning ✅</td><td>不重复。本系列 03、05 只点应用工程师必须知道的常识(记录类型、TTL、证书错误的常见症状),协议本身的字段、握手、状态机去 networkLearning</td></tr><tr><td>后端架构、容器、K8s</td><td>backendLearning ✅</td><td>不重复。本系列 11-12 只讲&quot;容器 / K8s 作为云产品&quot;的位置、成本、何时不该用,如何编写 Dockerfile / 写 K8s manifest 去 backendLearning</td></tr><tr><td>SRE、监控、事故复盘</td><td>devopsLearning ✅</td><td>不重复。本系列 18-25 只讲&quot;应用工程师看到 SLA / 监控 / 告警时该有的常识&quot;,真正做监控系统、写 Runbook、跑事故复盘去 devopsLearning</td></tr><tr><td>Web 安全、渗透测试</td><td>securityLearning ✅</td><td>不重复。本系列 26-33 只讲&quot;云服务用户必须配置对的东西&quot;(MFA、API Key 轮换、CORS),漏洞挖掘、攻击面分析去 securityLearning</td></tr><tr><td>系统设计、高可用</td><td>systemDesign ✅</td><td>不重复。本系列 25 容灾只讲&quot;云产品层面的可用性&quot;,大型分布式系统的多活、一致性、CAP 去 systemDesign</td></tr><tr><td>分布式系统理论</td><td>distributedLearning ✅</td><td>不重复。本系列只讲云产品视角的&quot;最终一致性&quot;、&quot;区域隔离&quot;,理论模型去那本</td></tr><tr><td>数据库 / 数据工程</td><td>backendLearning / dataEngineering</td><td>本系列 16 只讲&quot;托管数据库作为云产品&quot;的连接数、备份、定价,数据库内部和数据管道去那两本</td></tr><tr><td>终端 / SSH / dotfiles</td><td>terminalLearning ✅</td><td>不重复。本系列 09 提到云服务器时用 SSH,具体怎么用 SSH 去 terminalLearning</td></tr><tr><td>Claude Code / AI 工具</td><td>claudeLearning ✅</td><td>不重复。本系列只在 28 篇提到&quot;API Key 该怎么管&quot;时点一下 Anthropic / OpenAI Key 的存放,Claude Code 本身去那本</td></tr></tbody></table><p><strong>最简单粗暴的判断</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;我代码本身有问题&quot;                          → 各语言系列</span></span>
<span class="line"><span>&quot;我服务上线后 502 / 502 / timeout&quot;          → 本系列(01-08 排查)+ backendLearning</span></span>
<span class="line"><span>&quot;我账单超预算 / 套餐看不懂&quot;                 → 本系列(34-42)</span></span>
<span class="line"><span>&quot;我 K8s / Docker 不会用&quot;                    → backendLearning</span></span>
<span class="line"><span>&quot;我 Linux / SSH / shell 不会&quot;               → terminalLearning</span></span>
<span class="line"><span>&quot;我安全漏洞 / 渗透 / 防御&quot;                  → securityLearning</span></span>
<span class="line"><span>&quot;我监控 / 告警 / 事故复盘&quot;                  → devopsLearning</span></span>
<span class="line"><span>&quot;我系统设计大题&quot;                            → systemDesign</span></span>
<span class="line"><span>&quot;我 TCP / TLS 抓包&quot;                         → networkLearning</span></span>
<span class="line"><span>&quot;我 API Key 该怎么存 / 怎么轮换&quot;             → 本系列 28</span></span>
<span class="line"><span>&quot;我 DNS / HTTPS / CDN 怎么配&quot;                → 本系列 02-06</span></span></code></pre></div><p><strong>注意一个交叉点</strong>:<code>networkLearning</code> 讲协议(TCP 三次握手、TLS 1.3、HTTP/2 多路复用),本系列讲<strong>应用工程师视角下用云服务时该知道的协议常识</strong>——你不需要会画 TLS 握手图,但你需要知道「Cloudflare 的 Full (Strict) 模式比 Flexible 模式安全在哪、慢在哪」。<strong>两本结合读才完整</strong>:一本给你机制深度,一本给你应用宽度。</p><hr><h2 id="六、几个反直觉的事" tabindex="-1">六、几个反直觉的事 <a class="header-anchor" href="#六、几个反直觉的事" aria-label="Permalink to &quot;六、几个反直觉的事&quot;">​</a></h2><p>刚开始想认真学云服务常识,最容易卡在几个认知误区上。这一节把它们逐个打破——</p><h3 id="_6-1-我用-cloudflare-全免费-根本不用懂这些-——错在哪" tabindex="-1">6.1 &quot;我用 Cloudflare 全免费,根本不用懂这些&quot;——错在哪 <a class="header-anchor" href="#_6-1-我用-cloudflare-全免费-根本不用懂这些-——错在哪" aria-label="Permalink to &quot;6.1 &quot;我用 Cloudflare 全免费,根本不用懂这些&quot;——错在哪&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cloudflare 免费套餐的真实工作方式:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   用户请求</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       │ DNS 解析到 Cloudflare 边缘节点(免费)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>   Cloudflare 边缘节点(免费 CDN / SSL / DDoS 基础)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       │ Cache MISS 时回源</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>   你的源站 ← 这一段流量出了 Cloudflare,可能被你的源站厂商计费</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       │ 源站处理请求</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>   响应回到 Cloudflare → 用户</span></span></code></pre></div><p>Cloudflare 免费套餐解决的问题非常具体:<strong>边缘 CDN 缓存、HTTPS 证书、基础 DDoS 防护</strong>。但它<strong>不解决</strong>:</p><ul><li>你的源站(Vercel / AWS / VPS)的费用——回源流量、计算费、出站带宽都还在</li><li>WAF 规则(免费只给 5 条自定义规则)</li><li>Image Resizing(付费功能)</li><li>Cloudflare Workers(免费有调用次数和 CPU 时间上限)</li><li>Rate Limiting(免费有限制,复杂规则要付费)</li><li>Argo Smart Routing(付费功能)</li><li>你违反 ToS 时的封号(免费用户被封基本没救)</li></ul><p><strong>真相是</strong>:<strong>Cloudflare 免费套餐是&quot;边缘那一层免费&quot;,不是&quot;整套架构免费&quot;</strong>。当你的源站在 Vercel 上跑 Serverless,<strong>Cloudflare 帮你挡掉的是&quot;重复的静态资源请求&quot;,但只要有一次回源 Cloudflare 都不收钱,而 Vercel 那边的每一次 Function Invocation 全部照算</strong>。<strong>懂常识 = 知道 Cloudflare 在帮你省哪部分,不懂常识 = 以为&quot;挂上 Cloudflare 就免费&quot;</strong>。</p><h3 id="_6-2-serverless-完全不用管服务器-——真实代价被藏起来了" tabindex="-1">6.2 &quot;Serverless 完全不用管服务器&quot;——真实代价被藏起来了 <a class="header-anchor" href="#_6-2-serverless-完全不用管服务器-——真实代价被藏起来了" aria-label="Permalink to &quot;6.2 &quot;Serverless 完全不用管服务器&quot;——真实代价被藏起来了&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;无服务器&quot;的字面意思 vs 真实代价:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>字面意思:你不用买服务器、不用维护操作系统、不用扩容</span></span>
<span class="line"><span>真实代价:</span></span>
<span class="line"><span>   - 冷启动:函数 5-30 秒没人调用就被回收,下一次调用从零起 1-3 秒</span></span>
<span class="line"><span>   - 单次执行时间上限:Vercel 10 秒、AWS Lambda 15 分钟、Cloudflare Workers 50ms CPU</span></span>
<span class="line"><span>   - 并发限制:每个区域最大同时执行数,超了排队 / 拒绝</span></span>
<span class="line"><span>   - 数据库连接打爆:每个函数实例独立建连,瞬时高峰打爆 max_connections</span></span>
<span class="line"><span>   - 调用次数计费:每次调用算钱,白嫖型用户被反复 ping 一晚就破额度</span></span>
<span class="line"><span>   - 冷启动依赖:启动时装的包越多越慢,SDK 体积成本翻倍</span></span>
<span class="line"><span>   - 调试困难:本地跑得好好的,线上 timeout 不知道为什么</span></span></code></pre></div><p><strong>&quot;无服务器&quot;是一句营销话术</strong>,真实的 Serverless 是「<strong>把运维上的麻烦换成了配置上的麻烦,把固定成本换成了不可预测的变动成本</strong>」。<strong>适合用 Serverless 的场景非常窄</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>适合 Serverless:</span></span>
<span class="line"><span>   ✓ 偶发触发(Webhook、定时任务、低频 API)</span></span>
<span class="line"><span>   ✓ 短时执行(&lt; 1 秒,纯计算或简单 IO)</span></span>
<span class="line"><span>   ✓ 流量极度不均匀(99% 时间空闲,1% 时间需要瞬时扩 100 倍)</span></span>
<span class="line"><span>   ✓ 团队没人想运维(用户体验差一点也认了)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不适合 Serverless:</span></span>
<span class="line"><span>   ✗ 持续中等流量(改用 VPS / 长连接服务更便宜)</span></span>
<span class="line"><span>   ✗ 长时间任务(视频处理、AI 推理超 10 秒)</span></span>
<span class="line"><span>   ✗ 大量数据库连接(改用连接池 / 长连接更稳)</span></span>
<span class="line"><span>   ✗ 严格的延迟要求(P99 &lt; 100ms,冷启动会拉爆)</span></span>
<span class="line"><span>   ✗ 想精确控成本(按调用次数计费很难封顶)</span></span></code></pre></div><p><strong>结论</strong>:<strong>Serverless 不是 silver bullet,是一种特定场景下的工具</strong>。看到任何鼓吹「未来都是 Serverless」的文章,要在心里加一句:「<strong>对哪种场景的未来?</strong>」13 篇会展开讲这个。</p><h3 id="_6-3-99-9-sla-听起来很高-——它的意思可能不是你想的那样" tabindex="-1">6.3 &quot;99.9% SLA 听起来很高&quot;——它的意思可能不是你想的那样 <a class="header-anchor" href="#_6-3-99-9-sla-听起来很高-——它的意思可能不是你想的那样" aria-label="Permalink to &quot;6.3 &quot;99.9% SLA 听起来很高&quot;——它的意思可能不是你想的那样&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>99.9% SLA 的字面意思 vs 真实含义:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>字面意思:一年只能有 8.76 小时不可用</span></span>
<span class="line"><span>真实含义:</span></span>
<span class="line"><span>   - 不可用时间通常按&quot;连续故障 X 分钟&quot;统计,瞬时抖动不算</span></span>
<span class="line"><span>   - 计费周期通常是月,99.9% / 月 = 43.2 分钟不可用</span></span>
<span class="line"><span>   - SLA 违约的赔偿一般是&quot;按比例返还服务费&quot;——你一个月花 $20,</span></span>
<span class="line"><span>     赔你 $2,根本补不回你业务损失</span></span>
<span class="line"><span>   - 大部分 SLA 写明&quot;以下情况不算 downtime&quot;:</span></span>
<span class="line"><span>       * 计划内维护</span></span>
<span class="line"><span>       * 你自己的配置错误</span></span>
<span class="line"><span>       * 互联网骨干网问题</span></span>
<span class="line"><span>       * 上游 DNS 故障</span></span>
<span class="line"><span>       * 第三方依赖故障</span></span>
<span class="line"><span>       * 不可抗力</span></span>
<span class="line"><span>   - &quot;100% Uptime SLA&quot; 经常是法律意义上的——Cloudflare、</span></span>
<span class="line"><span>     Vercel 都写过,但赔偿条款一看,基本等于没有</span></span></code></pre></div><p><strong>真相是</strong>:<strong>SLA 是法律承诺,不是工程保证</strong>。云厂商承诺 99.99%,实际表现可能 99.95%——只要赔偿条款覆盖得过去,他们就敢写。<strong>对你来说</strong>,<strong>SLA 不是用来&quot;信&quot;的,是用来&quot;算&quot;的</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你应该这样看 SLA:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   厂商承诺 SLA:99.9%</span></span>
<span class="line"><span>   你的真实需求:不能让用户连续 30 分钟看不到登录页</span></span>
<span class="line"><span>   厂商承诺折算:99.9% / 月 = 最多 43 分钟不可用</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   结论:理论上够,但需要监控 + 备份方案,因为厂商可能集中故障一次性 30 分钟</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   厂商承诺 SLA:99.99%(对象存储)</span></span>
<span class="line"><span>   你的真实需求:文件不能丢,因为是用户付费上传的合同 PDF</span></span>
<span class="line"><span>   厂商承诺折算:99.99% Uptime 不等于 99.99% Durability(后者一般 11 个 9)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   结论:Uptime 和 Durability 是两件事,你要看后者</span></span></code></pre></div><p><strong>18-19 篇会展开讲 SLA / SLO / SLI 的区别</strong>,看完这两篇,你听到任何「99.9%、99.99%、100%」都会自动在心里问:「<strong>哪个维度的 99.9%?计费周期是月还是年?排除哪些情况?违约赔多少?</strong>」</p><h3 id="_6-4-我的项目还小-先免费用-等流量来了再升级-——升级的代价被低估了" tabindex="-1">6.4 &quot;我的项目还小,先免费用,等流量来了再升级&quot;——升级的代价被低估了 <a class="header-anchor" href="#_6-4-我的项目还小-先免费用-等流量来了再升级-——升级的代价被低估了" aria-label="Permalink to &quot;6.4 &quot;我的项目还小,先免费用,等流量来了再升级&quot;——升级的代价被低估了&quot;">​</a></h3><p>很多人觉得「免费套餐 → 付费套餐」是一个连续渐变的过程——<strong>实际上往往是悬崖</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>免费套餐 → 付费套餐的真实代价:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>平台              免费 → 最低付费              悬崖在哪</span></span>
<span class="line"><span>─────────────────────────────────────────────────────</span></span>
<span class="line"><span>Vercel           Hobby → Pro $20/月            从&quot;非商用&quot;变&quot;商用&quot;,</span></span>
<span class="line"><span>                                              SLA、并发、流量都跳一档</span></span>
<span class="line"><span>Cloudflare       Free → Pro $25/月             WAF 规则数、防火墙规则、</span></span>
<span class="line"><span>                                              Image Resizing 全跳</span></span>
<span class="line"><span>Supabase         Free → Pro $25/月             max_connections 60 → 200,</span></span>
<span class="line"><span>                                              存储 500MB → 8GB,要预先迁移</span></span>
<span class="line"><span>Netlify          Starter → Pro $19/月          构建分钟、Edge Function 调用</span></span>
<span class="line"><span>                                              数全跳</span></span>
<span class="line"><span>GitHub Actions   Free → 按分钟计               私有仓库每月 2000 分钟</span></span>
<span class="line"><span>                                              用完 $0.008/分钟</span></span>
<span class="line"><span>Cloudflare R2    Free → 按存储计               存储免费但 Class A 操作</span></span>
<span class="line"><span>                                              超 1M 开始计费</span></span></code></pre></div><p><strong>「等流量来了再升级」的隐藏成本</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- 流量来的那一刻,你大概率在做别的事(吃饭、睡觉、开会)</span></span>
<span class="line"><span>- 等你升级完,故障窗口已经过了,用户已经流失</span></span>
<span class="line"><span>- 升级有时候涉及数据迁移(Postgres 升级、对象存储换 region)</span></span>
<span class="line"><span>- 紧急升级时你会做出一堆事后后悔的配置决定</span></span>
<span class="line"><span>- 月底账单会因为&quot;试图救场&quot;的临时配置变得很难看</span></span></code></pre></div><p><strong>正确的做法是</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>项目从 0 开始时:</span></span>
<span class="line"><span>   ✓ 选免费套餐,但预先设好&quot;如果流量来了我会切到哪个套餐&quot;</span></span>
<span class="line"><span>   ✓ 把 worst-case 成本算出来,告诉自己&quot;这条线之前都还能接受&quot;</span></span>
<span class="line"><span>   ✓ 给账户加预算告警(免费套餐也能设)</span></span>
<span class="line"><span>   ✓ 不在免费套餐的&quot;硬天花板&quot;附近设计架构</span></span>
<span class="line"><span>     (例:Supabase max_connections=60 时,你的设计应该假设最多 30 并发)</span></span>
<span class="line"><span>   ✓ 关键功能(支付、登录)使用付费套餐,即便免费够用</span></span></code></pre></div><p><strong>这就是「云服务常识」在工程实践中的样子</strong>:不是「等出事再说」,而是「<strong>事前用 5 分钟做一个 worst-case 算账</strong>」。<strong>5 分钟换来一个不会让你半夜爬起来救火的架构,这就是常识的复利</strong>。</p><h3 id="_6-5-用最便宜的厂商就行-——隐藏成本经常超过显式价格" tabindex="-1">6.5 &quot;用最便宜的厂商就行&quot;——隐藏成本经常超过显式价格 <a class="header-anchor" href="#_6-5-用最便宜的厂商就行-——隐藏成本经常超过显式价格" aria-label="Permalink to &quot;6.5 &quot;用最便宜的厂商就行&quot;——隐藏成本经常超过显式价格&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;便宜&quot;的厂商常见隐藏代价:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>价格便宜的真实场景:</span></span>
<span class="line"><span>   - 出站流量贵(便宜的 EC2 配很贵的带宽,1TB 出站 $90)</span></span>
<span class="line"><span>   - 跨区域流量贵(同 region 免费,跨 region 一字千金)</span></span>
<span class="line"><span>   - 操作次数贵(便宜的对象存储,PUT/GET 一次 $0.0005,</span></span>
<span class="line"><span>     高频写入项目一个月 $200+)</span></span>
<span class="line"><span>   - 不收&quot;上车费&quot;但收&quot;下车费&quot;(数据 egress 费,迁出贵)</span></span>
<span class="line"><span>   - 默认配置安全性低(默认开放公网访问、默认明文存储)</span></span>
<span class="line"><span>   - SLA 低、客服差、文档烂(故障时全靠自己)</span></span>
<span class="line"><span>   - 区域少、节点少(国内用户访问海外厂商延迟 300ms+)</span></span>
<span class="line"><span>   - 合规缺(GDPR、ISO27001、SOC2 都没,出了事打不了官司)</span></span></code></pre></div><p><strong>应用工程师做选型时,真实成本 = 显式价格 + 出站流量 + 操作次数 + 迁移代价 + 故障期望损失 + 合规代价</strong>。<strong>而最便宜的厂商通常在「出站流量」和「迁移代价」上把钱赚回来</strong>——你免费用了一年,等想搬家时,数据迁出费用比这一年的存储费还贵。</p><p><strong>这就是 Cloudflare R2 这种&quot;零出口费&quot;产品的真实价值</strong>:<strong>不是它存储便宜(其实和 S3 差不多),而是它把&quot;被锁定&quot;这件事打破了</strong>。<strong>懂常识 = 看到价格表会找&quot;出口费&quot;那一行,不懂常识 = 看着 $0.015/GB 就觉得便宜,签了三年合同</strong>。</p><hr><h2 id="七、立场声明" tabindex="-1">七、立场声明 <a class="header-anchor" href="#七、立场声明" aria-label="Permalink to &quot;七、立场声明&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这个系列的写作立场,把它说在前面以免你期望落空:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✓ 服务于&quot;独立开发者 / 应用工程师 / 小团队 SaaS 创始人&quot;的视角</span></span>
<span class="line"><span>   不是企业架构师,不是 AWS Certified 备考者,不是 SRE</span></span>
<span class="line"><span>   读者画像是&quot;想把云服务这一层从黑盒变成白盒的应用工程师&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✓ 面向 2026 之后的云服务格局</span></span>
<span class="line"><span>   Cloudflare / Vercel / Supabase / R2 / Workers 是默认假设</span></span>
<span class="line"><span>   不写 AWS 单一厂商的全套,也不写 2015 年那套&quot;VPS 万岁&quot;</span></span>
<span class="line"><span>   不写国内特定厂商的备案细节,只在涉及合规时点一下</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✓ 通用概念优先,具体厂商次之</span></span>
<span class="line"><span>   每篇都先讲&quot;这个概念是什么&quot;、再举&quot;Cloudflare / Vercel / AWS / 阿里云怎么实现的&quot;</span></span>
<span class="line"><span>   不教你&quot;在 XX 控制台点 XX 按钮&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✓ 大量 ASCII 框图</span></span>
<span class="line"><span>   架构层级、请求链路、计费维度,画图比文字清楚 10 倍</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✓ 真实场景驱动</span></span>
<span class="line"><span>   每个概念都从一个&quot;账单暴涨 / 故障公告 / 配置错误&quot;的真实场景切入</span></span>
<span class="line"><span>   不堆术语定义</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不写&quot;AWS 全产品名录&quot;</span></span>
<span class="line"><span>   AWS 自己有 200+ 个产品,本系列只讲&quot;应用工程师需要知道的那些&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不抄云厂商官方文档</span></span>
<span class="line"><span>   官方文档在那儿,这里只补它没讲透的&quot;为什么&quot;和&quot;什么时候不要用&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不写&quot;AWS vs Azure vs GCP 哪个好&quot;式无脑对比</span></span>
<span class="line"><span>   每个厂商都有擅长场景,选型要看你自己的需求</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不写过时价格表</span></span>
<span class="line"><span>   价格和额度变化太快,只写&quot;查看方法&quot;,需要具体数字时标注查询日期</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不写&quot;我推荐 XX 厂商&quot;</span></span>
<span class="line"><span>   只讲选型逻辑,不带货</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✗ 不堆 flag,不抄 CLI 文档,不教 yaml 全字段</span></span>
<span class="line"><span>   只贴&quot;能跑、能改、能复现&quot;的最小片段</span></span></code></pre></div><p><strong>面向 2026:</strong></p><ul><li>假设你的项目 80% 用 Cloudflare / Vercel / Netlify / Supabase / Firebase 这类&quot;现代 PaaS&quot;</li><li>假设你的项目剩下 20% 可能用 AWS / 阿里云 / 腾讯云的具体产品</li><li>假设你已经会用 git、会写代码、会基本的 SSH 和 Docker</li><li>假设你不在乎&quot;是不是企业级&quot;,在乎&quot;够不够便宜、够不够稳、够不够快&quot;</li><li>假设你会用 Claude Code / ChatGPT 帮你写 yaml / Terraform,所以本系列不教 Terraform 语法</li></ul><hr><h2 id="八、读完整套你应该有的本能" tabindex="-1">八、读完整套你应该有的本能 <a class="header-anchor" href="#八、读完整套你应该有的本能" aria-label="Permalink to &quot;八、读完整套你应该有的本能&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>看到任何一个云服务产品页(免费套餐 / Pricing 页),</span></span>
<span class="line"><span>你下意识地做这几件事:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  □ 找&quot;免费额度&quot;的具体数字,看它被切成几个独立维度</span></span>
<span class="line"><span>  □ 找&quot;超额怎么算&quot;——是自动切付费、还是直接报错、还是降级</span></span>
<span class="line"><span>  □ 找&quot;硬限制&quot; vs &quot;软限制&quot;,硬限制(如 max_connections)在哪</span></span>
<span class="line"><span>  □ 找&quot;出站流量价格&quot;,这往往是隐藏的最大开销</span></span>
<span class="line"><span>  □ 找 &quot;Operations / Requests&quot; 计费,这往往是第二大开销</span></span>
<span class="line"><span>  □ 找 SLA 条款,看赔偿是不是法律意义上的</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>看到一个新项目的架构图,你下意识地问:</span></span>
<span class="line"><span>  □ 用户请求穿过几个云组件?每一个的成本和延迟是多少?</span></span>
<span class="line"><span>  □ 哪些组件在免费套餐,哪些在付费?</span></span>
<span class="line"><span>  □ worst-case 流量下,月成本会跳到哪个数字?</span></span>
<span class="line"><span>  □ 哪一层挂了,会让全站 down?哪一层挂了,只是降级?</span></span>
<span class="line"><span>  □ DNS / HTTPS / CDN / 源站 哪一层是单点?</span></span>
<span class="line"><span>  □ 数据存哪儿、跨区域吗、备份在哪、丢了能恢复吗</span></span>
<span class="line"><span></span></span>
<span class="line"><span>看到一份云服务账单,你下意识地问:</span></span>
<span class="line"><span>  □ 哪个产品占比最大?是不是预期内?</span></span>
<span class="line"><span>  □ 出站流量占多少?是不是被回源拖了?</span></span>
<span class="line"><span>  □ 有没有&quot;莫名其妙&quot;的产品出现(可能是被攻击 / 配置错误)</span></span>
<span class="line"><span>  □ 这个月有没有超出预算告警?为什么我没收到?</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>看到一份故障公告 / Status Page:</span></span>
<span class="line"><span>  □ 我用的是受影响的 region 吗?</span></span>
<span class="line"><span>  □ 我用的服务是受影响的产品吗?</span></span>
<span class="line"><span>  □ 受影响的是数据面还是控制面?</span></span>
<span class="line"><span>  □ 我有没有需要切到备份的依据(SLA 已经被违约了吗)</span></span></code></pre></div><p><strong>这套反射不是知识,是肌肉记忆</strong>——看到一个云产品页、一份架构图、一份账单,这些问题在你脑子里 30 秒跑完。<strong>这就是「懂云服务常识」和「用过云服务」的差别</strong>。</p><hr><h2 id="九、看完这一篇你应该能" tabindex="-1">九、看完这一篇你应该能 <a class="header-anchor" href="#九、看完这一篇你应该能" aria-label="Permalink to &quot;九、看完这一篇你应该能&quot;">​</a></h2><ul><li><strong>在白板上画出第三节那张「五层结构」全景图</strong>,讲清楚每一层在解决什么问题</li><li><strong>能反驳&quot;我用 Cloudflare 全免费就够&quot;这种说法</strong>,举得出 3 个免费套餐救不了的场景</li><li><strong>能区分「云服务常识」和「某家厂商的操作手册」</strong>——前者是通用认知,后者是具体技能</li><li><strong>能解释为什么 Serverless 不是 silver bullet</strong>,举出 3 个不适合 Serverless 的场景</li><li><strong>能解释 99.9% SLA 的真实含义</strong>,知道为什么&quot;100% Uptime SLA&quot;经常等于没承诺</li><li><strong>能根据自己的角色,选出本系列必读的篇目</strong>(独立开发 / SaaS 创始人 / 前端 / 后端 / AI 工程师)</li><li><strong>能讲清楚&quot;先免费、流量来了再升级&quot;的隐藏代价</strong>,说服自己事前做 worst-case 成本测算</li></ul><p>如果上面这 7 条你都能做到,<strong>这一篇就值了</strong>。</p><hr><h2 id="十、节奏建议" tabindex="-1">十、节奏建议 <a class="header-anchor" href="#十、节奏建议" aria-label="Permalink to &quot;十、节奏建议&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>建议阅读节奏:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 1 周:第一层 8 篇(本篇 + 02-08)</span></span>
<span class="line"><span>        互联网入口 / DNS / HTTPS / CDN,先把&quot;请求链路&quot;打通</span></span>
<span class="line"><span>        这一周可以拿一个自己的域名 + Cloudflare 实战一遍</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 2-3 周:第二层 9 篇(09-17)</span></span>
<span class="line"><span>        云资源全套,先看完再决定自己用什么</span></span>
<span class="line"><span>        这两周可以把一个边项目从 0 部署到上线</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 4 周:第三层 8 篇(18-25)</span></span>
<span class="line"><span>        SLA / 监控 / 备份,这一周给已有项目加一个监控</span></span>
<span class="line"><span>        即便用 UptimeRobot 这种免费工具也可以</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 5 周:第四层 8 篇(26-33)</span></span>
<span class="line"><span>        安全 / 权限 / 合规,这一周把账号 MFA、API Key 轮换、</span></span>
<span class="line"><span>        Root 隔离全部做掉</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 6-7 周:第五层 9 篇(34-42)</span></span>
<span class="line"><span>        计费 / 选型,这两周对照自己的项目做一次&quot;账单复盘&quot;</span></span>
<span class="line"><span>        把&quot;如果流量翻 10 倍我会被收多少钱&quot;算清楚</span></span>
<span class="line"><span></span></span>
<span class="line"><span>总耗时:6-8 周,大致一个半月到两个月</span></span></code></pre></div><p><strong>不要一口气读完</strong>——每读完一篇,<strong>至少在自己的项目里找一个对应的配置看看</strong>:看 Cloudflare DNS、看 Vercel 账单、看 Supabase 连接池、看对象存储的 CORS。<strong>光看不练等于没看,但有了这套常识地图,你练的每一次都是有方向的</strong>。</p><hr><h2 id="十一、踩坑提醒-总览版-后面每篇细讲" tabindex="-1">十一、踩坑提醒(总览版,后面每篇细讲) <a class="header-anchor" href="#十一、踩坑提醒-总览版-后面每篇细讲" aria-label="Permalink to &quot;十一、踩坑提醒(总览版,后面每篇细讲)&quot;">​</a></h2><p>后面 41 篇会逐个填这些坑,但这里先列出来——读完整个系列,你应该能避开这 15 个最常见的坑:</p><ol><li><strong>域名注册商和 DNS 托管混淆</strong>——NS 没改对,等 DNS 等一周</li><li><strong>HTTPS 证书过期忘了</strong>——Let&#39;s Encrypt 自动续期没设好,某天 SSL 错误吓走用户</li><li><strong>Cloudflare SSL 模式选错</strong>——选了 Flexible,中间人攻击门户敞开</li><li><strong>CDN 没缓存核心资源</strong>——回源费用爆表,Cloudflare 命中率 &lt; 50%</li><li><strong>WAF 当万能盾</strong>——以为有 WAF 就不用做参数校验</li><li><strong>VPS / Serverless 二选一焦虑</strong>——明明用 VPS 更便宜还非要上 Lambda</li><li><strong>对象存储 CORS 没配</strong>——前端上传文件全部 403</li><li><strong>数据库连接没用连接池</strong>——Serverless 函数把 Postgres 打爆</li><li><strong>Root 账号到处用</strong>——一旦 Key 泄露,整个账户被裸奔</li><li><strong>API Key 写代码里 commit</strong>——GitHub 上的 secret 一两小时被扫到、被白嫖</li><li><strong>CORS 配 <code>Access-Control-Allow-Origin: *</code></strong>——以为是&quot;调试方便&quot;,其实是漏洞</li><li><strong>没设预算告警</strong>——月底被账单震惊</li><li><strong>免费套餐计费维度看漏</strong>——以为只算流量,结果被 Function Invocations 收掉</li><li><strong>以为&quot;99.9% SLA&quot;=不会挂</strong>——挂的时候找不到备份方案</li><li><strong>被一家厂商锁定</strong>——数据出站费 &gt; 一年存储费,迁移不动</li></ol><p><strong>这 15 条每条后面都对应一篇文章</strong>——下面 41 篇就是这 15 条坑的逐个填补。</p><hr><h2 id="十二、小结-你为什么读这个系列" tabindex="-1">十二、小结:你为什么读这个系列 <a class="header-anchor" href="#十二、小结-你为什么读这个系列" aria-label="Permalink to &quot;十二、小结:你为什么读这个系列&quot;">​</a></h2><p>回到开篇:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;你不再只是会写代码的工程师&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>读完这个系列之后,你会:</span></span>
<span class="line"><span>   - 知道一个 HTTP 请求从用户到你代码,中间穿过哪些云组件</span></span>
<span class="line"><span>   - 知道任何一个&quot;免费套餐&quot;被切成了哪几个独立维度,各自的天花板在哪</span></span>
<span class="line"><span>   - 知道 SLA 数字背后是什么、哪些是法律承诺、哪些是工程保证</span></span>
<span class="line"><span>   - 知道云服务的&quot;显式价格&quot;之外还有出站流量、操作次数、迁移代价</span></span>
<span class="line"><span>   - 知道哪些事是云厂商负责、哪些事是你负责,出问题时该找谁</span></span>
<span class="line"><span>   - 知道任何一份架构图都该问&quot;成本最高在哪、单点最危险在哪&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最终,你成为团队里&quot;做技术选型时最不被市场文案带节奏&quot;的那个人</span></span>
<span class="line"><span>   不是装懂,是工程能力——</span></span>
<span class="line"><span>   - 同事问&quot;我们该用 Vercel 还是 Cloudflare Pages&quot;,你 1 分钟给方案</span></span>
<span class="line"><span>   - 同事问&quot;账单为什么 $200&quot;,你 30 秒能定位</span></span>
<span class="line"><span>   - 老板问&quot;上线之后流量翻 10 倍会怎样&quot;,你能立刻拉出 worst-case 表</span></span>
<span class="line"><span>   - 新人入职问&quot;DNS / CDN / WAF 怎么搭&quot;,你能 5 分钟讲清楚</span></span>
<span class="line"><span>   - 出故障时,你能在 10 分钟内判断&quot;是我们的锅还是云厂商的锅&quot;</span></span></code></pre></div><p><strong>云服务常识是应用工程师的&quot;成本意识 + 系统视角&quot;</strong>——你练一次,用一辈子;你不练,每次部署、每次扩容、每次出故障,都要重新付一遍学习税。</p><p><strong>国内市场对&quot;云服务常识&quot;长期低估</strong>——大家热衷讨论&quot;用什么框架&quot;、&quot;用什么 AI 工具&quot;,却很少有人把「<strong>云这一层</strong>」当成一项工程认知来对待。<strong>这种错位不会一直持续</strong>——一旦独立开发 / 副业项目 / 小团队 SaaS 在 2026 年成为主流,真正拉开差距的就不再是「会不会写代码」,而是「<strong>你能不能把一个想法低成本、高可用、安全地放到互联网上</strong>」。<strong>这种能力的核心,就是云服务常识</strong>。<strong>你提前练这套手艺,就是给自己积复利</strong>。</p><hr><p>下一篇:<strong><code>02-域名是什么:注册商、注册局、DNS 托管的区别.md</code></strong>——这一篇讲了「<strong>为什么</strong>要懂云服务常识」,下一篇讲「<strong>用户访问一个网站的第一步:域名</strong>」。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你买了一个 .com 域名,这背后发生了什么?</span></span>
<span class="line"><span>   - 你付钱的是&quot;注册商&quot;(GoDaddy / Cloudflare / 阿里云)</span></span>
<span class="line"><span>   - 真正分发的是&quot;注册局&quot;(Verisign 管 .com,PIR 管 .org)</span></span>
<span class="line"><span>   - 域名信息存在&quot;WHOIS / RDAP&quot;里</span></span>
<span class="line"><span>   - &quot;DNS 托管&quot;是另一个独立服务(可能在注册商,也可能在第三方)</span></span>
<span class="line"><span>   - 浏览器要先查&quot;递归 DNS&quot;(运营商或公共 DNS)</span></span>
<span class="line"><span>   - 递归 DNS 找&quot;权威 DNS&quot;(你 NS 指向的地方)</span></span>
<span class="line"><span>   - 权威 DNS 返回 A / AAAA / CNAME 记录</span></span></code></pre></div><p>这一套东西不画图永远讲不清楚,02 篇会把它一图打通。<strong>看完 02 你应该能在白板上画出「域名注册 → 用户访问」的完整链路,并指出每一步如果出错会看到什么现象</strong>——这套图建好,后面 40 篇的所有概念(CDN 为什么要 CNAME / 邮件为什么用 MX / DNSSEC 解决什么)就都有了挂靠点。</p>`,121)])])}const q=n(e,[["render",t]]);export{g as __pageData,q as default};
